#!/usr/bin/env node
const { spawn, execSync } = require('child_process')
const path = require('path')
const fs = require('fs') 

const NODE_BIN = process.env.NODE_BIN || '/usr/local/bin/node' 

module.exports = {
  start () {
    return new Promise((resolve, reject) => {
      console.log('🚀 Starting backend websocket daemon...')
 
      const serverPath = path.join(__dirname, './daemon.js')

      if (!fs.existsSync(serverPath)) {
          console.error(`❌ FAILED: Cannot find daemon.js. Looked at: ${serverPath}`)
          console.error(`(Check the path calculation in websocketd/index.js)`)
          return reject(new Error(`daemon.js not found at ${serverPath}`))
      }

      try {
        const child = spawn(NODE_BIN, [serverPath], {
          detached: true,
          stdio: 'ignore',
          env: process.env 
        })
        child.unref()
        
        setTimeout(() => {
           console.log('✅ WebSocket daemon started (process launched).')
           resolve()
        }, 1000) 

      } catch (err) { 
        console.error('❌ Failed to start WebSocket daemon:', err.message)
        reject(err)
      }
    })
  },

  stop (){
    console.log('🛑 Stopping backend websocket daemon...')
    try {
      execSync('pkill -f lib/node_modules/websocketd/daemon.js', { stdio: 'ignore' })
      console.log('✅ WebSocket daemon stopped.')
    } catch {
      console.log('No websocket daemon found.')
    }
  }
}